const ALLOWED_SCRIPT_FUNCTIONS = [
  '_score', 'doc', 'Math.log', 'Math.sqrt', 'Math.abs', 'Math.pow',
  'Math.max', 'Math.min', 'Math.floor', 'Math.ceil', 'Math.round',
  'params', 'saturation', 'sigmoid', 'randomScore', 'fieldValueFactor',
  'decayDateGauss', 'decayDateExp', 'decayDateLinear',
  'decayGeoGauss', 'decayGeoExp', 'decayGeoLinear',
  'decayNumericGauss', 'decayNumericExp', 'decayNumericLinear'
];

const FORBIDDEN_PATTERNS = [
  /Runtime/i, /Process/i, /System\.exit/i, /exec/i, /eval/i,
  /Thread/i, /Class\.forName/i, /getRuntime/i, /ProcessBuilder/i,
  /import\s/i, /java\./i, /javax\./i, /org\.elasticsearch\.action/i,
  /File/i, /Socket/i, /URL\(/i, /HttpURLConnection/i
];

function validateScript(scriptSource) {
  if (!scriptSource || typeof scriptSource !== 'string') {
    return { valid: false, reason: 'Script source must be a non-empty string' };
  }

  if (scriptSource.length > 2000) {
    return { valid: false, reason: 'Script source exceeds maximum length of 2000 characters' };
  }

  for (const pattern of FORBIDDEN_PATTERNS) {
    if (pattern.test(scriptSource)) {
      return { valid: false, reason: `Script contains forbidden pattern: ${pattern}` };
    }
  }

  return { valid: true };
}

function buildBaseQuery(searchParams) {
  const {
    query_string, fields, filters, must, must_not, should,
    minimum_should_match, nested_queries, range_filters,
    geo_filters, aggregations, highlight, sort, from, size,
    fuzzy, prefix, wildcard, match_phrase, multi_match_type
  } = searchParams;

  const boolQuery = {
    must: [],
    must_not: [],
    should: [],
    filter: []
  };

  // Main query string
  if (query_string) {
    if (fields && fields.length > 0) {
      boolQuery.must.push({
        multi_match: {
          query: query_string,
          fields: fields,
          type: multi_match_type || 'best_fields',
          fuzziness: fuzzy ? 'AUTO' : undefined
        }
      });
    } else {
      boolQuery.must.push({
        query_string: {
          query: query_string,
          default_operator: 'AND'
        }
      });
    }
  }

  // Match phrase queries
  if (match_phrase) {
    for (const [field, phrase] of Object.entries(match_phrase)) {
      boolQuery.must.push({
        match_phrase: { [field]: phrase }
      });
    }
  }

  // Prefix queries
  if (prefix) {
    for (const [field, value] of Object.entries(prefix)) {
      boolQuery.must.push({
        prefix: { [field]: { value: value } }
      });
    }
  }

  // Wildcard queries
  if (wildcard) {
    for (const [field, value] of Object.entries(wildcard)) {
      boolQuery.must.push({
        wildcard: { [field]: { value: value } }
      });
    }
  }

  // Must clauses
  if (must && Array.isArray(must)) {
    for (const clause of must) {
      if (clause.match) {
        boolQuery.must.push({ match: clause.match });
      } else if (clause.term) {
        boolQuery.must.push({ term: clause.term });
      } else if (clause.terms) {
        boolQuery.must.push({ terms: clause.terms });
      } else if (clause.exists) {
        boolQuery.must.push({ exists: clause.exists });
      } else {
        boolQuery.must.push(clause);
      }
    }
  }

  // Must not clauses
  if (must_not && Array.isArray(must_not)) {
    for (const clause of must_not) {
      boolQuery.must_not.push(clause);
    }
  }

  // Should clauses
  if (should && Array.isArray(should)) {
    for (const clause of should) {
      boolQuery.should.push(clause);
    }
    if (minimum_should_match) {
      boolQuery.minimum_should_match = minimum_should_match;
    }
  }

  // Term/keyword filters
  if (filters) {
    for (const [field, value] of Object.entries(filters)) {
      if (Array.isArray(value)) {
        boolQuery.filter.push({ terms: { [field]: value } });
      } else {
        boolQuery.filter.push({ term: { [field]: value } });
      }
    }
  }

  // Range filters
  if (range_filters) {
    for (const [field, range] of Object.entries(range_filters)) {
      boolQuery.filter.push({ range: { [field]: range } });
    }
  }

  // Geo filters
  if (geo_filters) {
    if (geo_filters.geo_distance) {
      boolQuery.filter.push({
        geo_distance: {
          distance: geo_filters.geo_distance.distance,
          [geo_filters.geo_distance.field]: geo_filters.geo_distance.location
        }
      });
    }
    if (geo_filters.geo_bounding_box) {
      boolQuery.filter.push({
        geo_bounding_box: {
          [geo_filters.geo_bounding_box.field]: geo_filters.geo_bounding_box.box
        }
      });
    }
  }

  // Nested queries
  if (nested_queries && Array.isArray(nested_queries)) {
    for (const nestedQuery of nested_queries) {
      boolQuery.must.push({
        nested: {
          path: nestedQuery.path,
          query: nestedQuery.query,
          score_mode: nestedQuery.score_mode || 'avg'
        }
      });
    }
  }

  // Clean up empty arrays
  if (boolQuery.must.length === 0) delete boolQuery.must;
  if (boolQuery.must_not.length === 0) delete boolQuery.must_not;
  if (boolQuery.should.length === 0) delete boolQuery.should;
  if (boolQuery.filter.length === 0) delete boolQuery.filter;

  // If bool query is empty, use match_all
  const hasClause = boolQuery.must || boolQuery.must_not || boolQuery.should || boolQuery.filter;
  const query = hasClause ? { bool: boolQuery } : { match_all: {} };

  // Build the full search body
  const searchBody = {
    query: query,
    from: from || 0,
    size: size || 10
  };

  // Sort
  if (sort && Array.isArray(sort)) {
    searchBody.sort = sort;
  }

  // Highlight
  if (highlight) {
    searchBody.highlight = {
      fields: {},
      pre_tags: highlight.pre_tags || ['<em>'],
      post_tags: highlight.post_tags || ['</em>'],
      fragment_size: highlight.fragment_size || 150,
      number_of_fragments: highlight.number_of_fragments || 3
    };
    const highlightFields = highlight.fields || fields || ['*'];
    for (const field of highlightFields) {
      const fieldName = typeof field === 'string' ? field.replace(/\^[\d.]+$/, '') : field;
      searchBody.highlight.fields[fieldName] = {};
    }
  }

  // Aggregations
  if (aggregations) {
    searchBody.aggs = {};
    for (const [aggName, aggConfig] of Object.entries(aggregations)) {
      searchBody.aggs[aggName] = buildAggregation(aggConfig);
    }
  }

  return searchBody;
}

function buildAggregation(aggConfig) {
  const agg = {};

  if (aggConfig.type === 'terms') {
    agg.terms = {
      field: aggConfig.field,
      size: aggConfig.size || 10,
      order: aggConfig.order || undefined
    };
  } else if (aggConfig.type === 'range') {
    agg.range = {
      field: aggConfig.field,
      ranges: aggConfig.ranges
    };
  } else if (aggConfig.type === 'date_histogram') {
    agg.date_histogram = {
      field: aggConfig.field,
      calendar_interval: aggConfig.calendar_interval || aggConfig.interval || 'month',
      format: aggConfig.format || 'yyyy-MM-dd',
      min_doc_count: aggConfig.min_doc_count || 0
    };
  } else if (aggConfig.type === 'histogram') {
    agg.histogram = {
      field: aggConfig.field,
      interval: aggConfig.interval,
      min_doc_count: aggConfig.min_doc_count || 0
    };
  } else if (aggConfig.type === 'avg' || aggConfig.type === 'sum' ||
             aggConfig.type === 'min' || aggConfig.type === 'max' ||
             aggConfig.type === 'cardinality' || aggConfig.type === 'value_count') {
    agg[aggConfig.type] = { field: aggConfig.field };
  } else if (aggConfig.type === 'nested') {
    agg.nested = { path: aggConfig.path };
  } else if (aggConfig.type === 'filter') {
    agg.filter = aggConfig.filter;
  } else if (aggConfig.type === 'stats' || aggConfig.type === 'extended_stats') {
    agg[aggConfig.type] = { field: aggConfig.field };
  } else if (aggConfig.type === 'percentiles') {
    agg.percentiles = {
      field: aggConfig.field,
      percents: aggConfig.percents || [25, 50, 75, 95, 99]
    };
  }

  // Sub-aggregations
  if (aggConfig.aggs) {
    agg.aggs = {};
    for (const [subAggName, subAggConfig] of Object.entries(aggConfig.aggs)) {
      agg.aggs[subAggName] = buildAggregation(subAggConfig);
    }
  }

  return agg;
}

function applyScriptScore(searchBody, scoringConfig) {
  const { script_source, script_lang, script_params, max_boost, min_score } = scoringConfig;

  const validation = validateScript(script_source);
  if (!validation.valid) {
    throw new Error(`Invalid scoring script: ${validation.reason}`);
  }

  const originalQuery = searchBody.query;

  searchBody.query = {
    script_score: {
      query: originalQuery,
      script: {
        source: script_source,
        lang: script_lang || 'painless',
        params: script_params || {}
      }
    }
  };

  if (max_boost) {
    searchBody.query.script_score.max_boost = max_boost;
  }

  if (min_score) {
    searchBody.min_score = min_score;
  }

  return searchBody;
}

function applyFunctionScore(searchBody, functionScoreConfig) {
  const {
    functions, score_mode, boost_mode, max_boost, min_score
  } = functionScoreConfig;

  const originalQuery = searchBody.query;
  const scoreFunctions = [];

  if (functions && Array.isArray(functions)) {
    for (const func of functions) {
      const scoreFunction = {};

      if (func.filter) {
        scoreFunction.filter = func.filter;
      }

      if (func.weight) {
        scoreFunction.weight = func.weight;
      }

      if (func.script_score) {
        const validation = validateScript(func.script_score.script.source);
        if (!validation.valid) {
          throw new Error(`Invalid function score script: ${validation.reason}`);
        }
        scoreFunction.script_score = func.script_score;
      }

      if (func.field_value_factor) {
        scoreFunction.field_value_factor = {
          field: func.field_value_factor.field,
          factor: func.field_value_factor.factor || 1,
          modifier: func.field_value_factor.modifier || 'none',
          missing: func.field_value_factor.missing || 1
        };
      }

      if (func.random_score) {
        scoreFunction.random_score = {
          seed: func.random_score.seed,
          field: func.random_score.field || '_seq_no'
        };
      }

      if (func.decay) {
        const decayType = func.decay.type || 'gauss';
        scoreFunction[decayType] = {
          [func.decay.field]: {
            origin: func.decay.origin,
            scale: func.decay.scale,
            offset: func.decay.offset || '0',
            decay: func.decay.decay || 0.5
          }
        };
      }

      scoreFunctions.push(scoreFunction);
    }
  }

  searchBody.query = {
    function_score: {
      query: originalQuery,
      functions: scoreFunctions,
      score_mode: score_mode || 'multiply',
      boost_mode: boost_mode || 'multiply'
    }
  };

  if (max_boost) {
    searchBody.query.function_score.max_boost = max_boost;
  }

  if (min_score) {
    searchBody.min_score = min_score;
  }

  return searchBody;
}

