// Main search endpoint
app.post('/search/:index', async (req, res) => {
  try {
    const { index } = req.params;
    const {
      search_params,
      scoring,
      function_score,
      explain,
      track_total_hits,
      _source,
      stored_fields,
      docvalue_fields,
      collapse,
      search_after,
      pit
    } = req.body;

    if (!search_params) {
      return res.status(400).json({
        error: 'search_params is required'
      });
    }

    // Build base query
    let searchBody = buildBaseQuery(search_params);

    // Apply script_score if provided
    if (scoring) {
      searchBody = applyScriptScore(searchBody, scoring);
    }

    // Apply function_score if provided (mutually exclusive with script_score)
    if (function_score && !scoring) {
      searchBody = applyFunctionScore(searchBody, function_score);
    }

    // Source filtering
    if (_source !== undefined) {
      searchBody._source = _source;
    }

    if (stored_fields) {
      searchBody.stored_fields = stored_fields;
    }

    if (docvalue_fields) {
      searchBody.docvalue_fields = docvalue_fields;
    }

    // Field collapsing
    if (collapse) {
      searchBody.collapse = collapse;
    }

    // Search after (for deep pagination)
    if (search_after) {
      searchBody.search_after = search_after;
    }

    // Track total hits
    if (track_total_hits !== undefined) {
      searchBody.track_total_hits = track_total_hits;
    }

    const searchParams = {
      index: index,
      body: searchBody,
      explain: explain || false
    };

    // Point in time
    if (pit) {
      searchParams.body.pit = pit;
      delete searchParams.index;
    }

    const result = await esClient.search(searchParams);

    res.json({
      took: result.took,
      timed_out: result.timed_out,
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map(hit => ({
        _index: hit._index,
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
        highlight: hit.highlight,
        sort: hit.sort,
        _explanation: hit._explanation,
        fields: hit.fields,
        inner_hits: hit.inner_hits
      })),
      aggregations: result.aggregations,
      pit_id: result.pit_id,
      _query_dsl: searchBody
    });
  } catch (error) {
    console.error('Search error:', error);
    res.status(error.statusCode || 500).json({
      error: error.message,
      details: error.meta?.body?.error || null
    });
  }
});

