// Multi-search endpoint
app.post('/msearch', async (req, res) => {
  try {
    const { searches } = req.body;

    if (!searches || !Array.isArray(searches)) {
      return res.status(400).json({
        error: 'searches array is required'
      });
    }

    const body = [];
    for (const search of searches) {
      const { index, search_params, scoring, function_score } = search;

      body.push({ index });

      let searchBody = buildBaseQuery(search_params);

      if (scoring) {
        searchBody = applyScriptScore(searchBody, scoring);
      }

      if (function_score && !scoring) {
        searchBody = applyFunctionScore(searchBody, function_score);
      }

      body.push(searchBody);
    }

    const result = await esClient.msearch({ body });

    res.json({
      responses: result.responses.map((response, idx) => ({
        search_index: idx,
        took: response.took,
        timed_out: response.timed_out,
        total: response.hits?.total,
        max_score: response.hits?.max_score,
        hits: response.hits?.hits?.map(hit => ({
          _index: hit._index,
          _id: hit._id,
          _score: hit._score,
          _source: hit._source,
          highlight: hit.highlight
        })),
        aggregations: response.aggregations,
        error: response.error
      }))
    });
  } catch (error) {
    console.error('Multi-search error:', error);
    res.status(error.statusCode || 500).json({
      error: error.message,
      details: error.meta?.body?.error || null
    });
  }
});

