// Scoring templates: save and retrieve reusable scoring configurations
const scoringTemplates = new Map();

app.post('/scoring-templates', (req, res) => {
  const { name, description, scoring_config } = req.body;

  if (!name || !scoring_config) {
    return res.status(400).json({
      error: 'name and scoring_config are required'
    });
  }

  // Validate scripts in the template
  if (scoring_config.script_source) {
    const validation = validateScript(scoring_config.script_source);
    if (!validation.valid) {
      return res.status(400).json({
        error: `Invalid script in template: ${validation.reason}`
      });
    }
  }

  if (scoring_config.functions) {
    for (const func of scoring_config.functions) {
      if (func.script_score?.script?.source) {
        const validation = validateScript(func.script_score.script.source);
        if (!validation.valid) {
          return res.status(400).json({
            error: `Invalid function script in template: ${validation.reason}`
          });
        }
      }
    }
  }

  scoringTemplates.set(name, {
    name,
    description,
    scoring_config,
    created_at: new Date().toISOString()
  });

  res.status(201).json({
    message: 'Scoring template saved',
    template: scoringTemplates.get(name)
  });
});

app.get('/scoring-templates', (req, res) => {
  res.json({
    templates: Array.from(scoringTemplates.values())
  });
});

app.get('/scoring-templates/:name', (req, res) => {
  const template = scoringTemplates.get(req.params.name);
  if (!template) {
    return res.status(404).json({ error: 'Template not found' });
  }
  res.json({ template });
});

app.delete('/scoring-templates/:name', (req, res) => {
  if (!scoringTemplates.has(req.params.name)) {
    return res.status(404).json({ error: 'Template not found' });
  }
  scoringTemplates.delete(req.params.name);
  res.json({ message: 'Template deleted' });
});

// Search using a scoring template
app.post('/search-with-template/:index', async (req, res) => {
  try {
    const { index } = req.params;
    const { search_params, template_name, template_params, explain } = req.body;

    if (!search_params || !template_name) {
      return res.status(400).json({
        error: 'search_params and template_name are required'
      });
    }

    const template = scoringTemplates.get(template_name);
    if (!template) {
      return res.status(404).json({ error: 'Scoring template not found' });
    }

    let searchBody = buildBaseQuery(search_params);

    // Deep clone the scoring config and merge template_params
    const scoringConfig = JSON.parse(JSON.stringify(template.scoring_config));

    if (template_params && scoringConfig.script_params) {
      scoringConfig.script_params = {
        ...scoringConfig.script_params,
        ...template_params
      };
    }

    if (scoringConfig.script_source) {
      searchBody = applyScriptScore(searchBody, scoringConfig);
    } else if (scoringConfig.functions) {
      searchBody = applyFunctionScore(searchBody, scoringConfig);
    }

    const result = await esClient.search({
      index,
      body: searchBody,
      explain: explain || false
    });

    res.json({
      took: result.took,
      timed_out: result.timed_out,
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map(hit => ({
        _index: hit._index,
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
        highlight: hit.highlight,
        _explanation: hit._explanation
      })),
      aggregations: result.aggregations,
      template_used: template_name,
      _query_dsl: searchBody
    });
  } catch (error) {
    console.error('Template search error:', error);
    res.status(error.statusCode || 500).json({
      error: error.message,
      details: error.meta?.body?.error || null
    });
  }
});

